import{_ as e,o,c as d,ag as c}from"./chunks/framework-C5-Jzrz4.js";const a=JSON.parse('{"title":"核心接口说明","description":"认证、菜单、用户等核心 API 与数据格式说明","frontmatter":{"title":"核心接口说明","description":"认证、菜单、用户等核心 API 与数据格式说明"},"headers":[],"relativePath":"scripts/api/核心接口说明.md","filePath":"scripts/api/核心接口说明.md","lastUpdated":null}');const i=e({name:"scripts/api/核心接口说明.md"},[["render",function(e,a,i,l,t,r){return o(),d("div",null,[...a[0]||(a[0]=[c('<h1 id="核心接口说明" tabindex="-1">核心接口说明 <a class="header-anchor" href="#核心接口说明" aria-label="Permalink to &quot;核心接口说明&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本页按“认证与会话、菜单与用户、系统管理”整理当前项目核心接口，所有结论基于现有 <code>index.ts</code> 与类型定义。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>登录与鉴权链路联调</li><li>菜单、用户、角色等基础模块开发</li><li>快速确认分页与错误码返回格式</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/src/api/core/{auth,menu,user}.ts</code></li><li><code>apps/web-antd/src/api/system/{user,role,menu,dict}</code></li><li><code>apps/web-antd/src/api/common.d.ts</code></li><li><code>apps/web-antd/src/utils/http/index.ts</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="认证与会话-api-core-auth-ts" tabindex="-1">认证与会话（<code>api/core/auth.ts</code>） <a class="header-anchor" href="#认证与会话-api-core-auth-ts" aria-label="Permalink to &quot;认证与会话（`api/core/auth.ts`）&quot;">​</a></h3><ul><li><code>loginApi(data)</code>：<code>POST /auth/login</code>，默认附带 <code>clientId</code>，并开启 <code>encrypt: true</code></li><li><code>doLogout()</code>：<code>POST /auth/logout</code></li><li><code>tenantList()</code>：<code>GET /auth/tenant/list</code></li><li><code>authBinding(source, tenantId)</code>：第三方绑定地址</li><li><code>authCallback(data)</code>：<code>POST /auth/social/callback</code></li></ul><p>关键类型：</p><ul><li><code>AuthApi.LoginParams</code>（<code>SimpleLoginParams | OAuthLoginParams</code>）</li><li><code>AuthApi.LoginResult</code>（<code>access_token/client_id/expire_in</code>）</li><li><code>TenantResp</code>（<code>tenantEnabled</code>、<code>voList</code>）</li></ul><h3 id="菜单与用户基础信息-api-core-menu-ts、api-core-user-ts" tabindex="-1">菜单与用户基础信息（<code>api/core/menu.ts</code>、<code>api/core/user.ts</code>） <a class="header-anchor" href="#菜单与用户基础信息-api-core-menu-ts、api-core-user-ts" aria-label="Permalink to &quot;菜单与用户基础信息（`api/core/menu.ts`、`api/core/user.ts`）&quot;">​</a></h3><ul><li><code>getAllMenusApi()</code>：<code>GET /system/menu/getRouters</code></li><li><code>getUserInfoApi()</code>：<code>GET /system/user/getInfo</code></li></ul><p>关键类型：</p><ul><li><code>Menu</code> / <code>MenuMeta</code></li><li><code>UserInfoResp</code></li><li><code>User</code> / <code>Role</code></li></ul><h3 id="系统管理高频模块" tabindex="-1">系统管理高频模块 <a class="header-anchor" href="#系统管理高频模块" aria-label="Permalink to &quot;系统管理高频模块&quot;">​</a></h3><ul><li>用户（<code>api/system/user/index.ts</code>） <ul><li><code>userList</code>、<code>findUserInfo</code>、<code>userAdd</code>、<code>userUpdate</code>、<code>userRemove</code></li><li><code>userResetPassword</code> 使用 <code>encrypt: true</code></li></ul></li><li>角色（<code>api/system/role/index.ts</code>） <ul><li><code>roleList</code>、<code>roleInfo</code>、<code>roleAdd</code>、<code>roleUpdate</code>、<code>roleRemove</code></li><li><code>roleDataScope</code>、角色授权相关接口</li></ul></li><li>菜单（<code>api/system/menu/index.ts</code>） <ul><li><code>menuList</code>、<code>menuInfo</code>、<code>menuAdd</code>、<code>menuUpdate</code>、<code>menuRemove</code></li><li><code>menuTreeSelect</code>、<code>roleMenuTreeSelect</code></li></ul></li><li>字典（<code>api/system/dict/*</code>） <ul><li><code>dictDataInfo</code>、<code>dictDataList</code></li><li><code>dictTypeList</code>、<code>dictTypeInfo</code></li></ul></li></ul><h3 id="分页与返回格式" tabindex="-1">分页与返回格式 <a class="header-anchor" href="#分页与返回格式" aria-label="Permalink to &quot;分页与返回格式&quot;">​</a></h3><ul><li>通用分页类型：<code>PageResult&lt;T&gt; = { rows: T[]; total: number }</code></li><li>请求层成功码：<code>BUSINESS_SUCCESS_CODE = 200</code></li><li>未授权码：<code>UNAUTHORIZED_CODE = 401</code></li><li>成功返回时： <ul><li>有 <code>data</code> 字段返回 <code>data</code></li><li>无 <code>data</code>（常见分页）返回 <code>{ rows, total, ... }</code></li></ul></li></ul><h3 id="错误处理与提示" tabindex="-1">错误处理与提示 <a class="header-anchor" href="#错误处理与提示" aria-label="Permalink to &quot;错误处理与提示&quot;">​</a></h3><ul><li>HTTP 错误由 <code>checkStatus</code> 统一映射提示</li><li>401 触发 <code>handleUnauthorizedLogout()</code> 统一登出流程</li><li>可选 <code>getWithMsg/postWithMsg/putWithMsg/deleteWithMsg</code> 触发成功提示</li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>业务代码引用核心接口可直接 <code>from &#39;#/api&#39;</code>，系统模块需按目录路径导入。</li><li>设计新接口时，优先复用 <code>PageQuery</code>、<code>PageResult</code>、<code>ID/IDS</code> 等通用类型。</li><li>发现接口文档与实现不一致时，以 <code>apps/web-antd/src/api</code> 与 <code>utils/http</code> 实际代码为准。</li></ul>',24)])])}]]);export{a as __pageData,i as default};
